from __future__ import annotations

import sqlite3
from pathlib import Path
from typing import Any


class BrowserStore:
    def __init__(self, path: Path | None = None) -> None:
        data_dir = Path.home() / ".local" / "share" / "trowser"
        self.path = path or data_dir / "trowser.db"
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self.db = sqlite3.connect(self.path)
        self.db.row_factory = sqlite3.Row
        self.db.executescript(
            """
            CREATE TABLE IF NOT EXISTS bookmarks (
                url TEXT PRIMARY KEY,
                title TEXT NOT NULL,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );
            CREATE TABLE IF NOT EXISTS history (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                url TEXT NOT NULL,
                title TEXT NOT NULL,
                visited_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );
            CREATE INDEX IF NOT EXISTS history_visited_at
                ON history(visited_at DESC);
            CREATE TABLE IF NOT EXISTS settings (
                key TEXT PRIMARY KEY,
                value TEXT NOT NULL
            );
            """
        )

    def add_bookmark(self, url: str, title: str) -> None:
        self.db.execute(
            """
            INSERT INTO bookmarks(url, title) VALUES (?, ?)
            ON CONFLICT(url) DO UPDATE SET title = excluded.title
            """,
            (url, title or url),
        )
        self.db.commit()

    def remove_bookmark(self, url: str) -> None:
        self.db.execute("DELETE FROM bookmarks WHERE url = ?", (url,))
        self.db.commit()

    def is_bookmarked(self, url: str) -> bool:
        row = self.db.execute(
            "SELECT 1 FROM bookmarks WHERE url = ?", (url,)
        ).fetchone()
        return row is not None

    def bookmarks(self) -> list[dict[str, Any]]:
        rows = self.db.execute(
            "SELECT url, title, created_at FROM bookmarks ORDER BY title COLLATE NOCASE"
        ).fetchall()
        return [dict(row) for row in rows]

    def merge_bookmarks(self, bookmarks: list[dict[str, str]]) -> None:
        for bookmark in bookmarks:
            url = bookmark.get("url", "")
            if url.startswith(("http://", "https://")):
                self.db.execute(
                    """
                    INSERT INTO bookmarks(url, title) VALUES (?, ?)
                    ON CONFLICT(url) DO UPDATE SET title = excluded.title
                    """,
                    (url, bookmark.get("title") or url),
                )
        self.db.commit()

    def setting(self, key: str, default: str = "") -> str:
        row = self.db.execute(
            "SELECT value FROM settings WHERE key = ?", (key,)
        ).fetchone()
        return row["value"] if row else default

    def set_setting(self, key: str, value: str) -> None:
        self.db.execute(
            """
            INSERT INTO settings(key, value) VALUES (?, ?)
            ON CONFLICT(key) DO UPDATE SET value = excluded.value
            """,
            (key, value),
        )
        self.db.commit()

    def settings(self) -> dict[str, str]:
        rows = self.db.execute("SELECT key, value FROM settings").fetchall()
        return {row["key"]: row["value"] for row in rows}

    def merge_settings(self, settings: dict[str, str]) -> None:
        for key, value in settings.items():
            if isinstance(key, str) and isinstance(value, str):
                self.set_setting(key, value)

    def add_history(self, url: str, title: str) -> None:
        if not url.startswith(("http://", "https://", "file://")):
            return
        latest = self.db.execute(
            "SELECT url FROM history ORDER BY id DESC LIMIT 1"
        ).fetchone()
        if latest and latest["url"] == url:
            self.db.execute(
                "UPDATE history SET title = ?, visited_at = CURRENT_TIMESTAMP "
                "WHERE id = (SELECT MAX(id) FROM history)",
                (title or url,),
            )
        else:
            self.db.execute(
                "INSERT INTO history(url, title) VALUES (?, ?)", (url, title or url)
            )
        self.db.commit()

    def history(self, limit: int = 250) -> list[dict[str, Any]]:
        rows = self.db.execute(
            "SELECT id, url, title, visited_at FROM history "
            "ORDER BY id DESC LIMIT ?",
            (limit,),
        ).fetchall()
        return [dict(row) for row in rows]

    def clear_history(self) -> None:
        self.db.execute("DELETE FROM history")
        self.db.commit()

    def close(self) -> None:
        self.db.close()
